```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input buffer
    std::vector<uint8_t> buffer_copy(buffer.begin(), buffer.end());
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer_copy);

    NetworkPacket packet;

    // Read packet_id using arithmetic deserialization
    adaptor >> packet.packet_id;

    // Read username using prefixed string deserialization
    adaptor >> hexi::prefixed(packet.username);

    // Read scores vector: first read count, then use read_container
    uint32_t score_count;
    adaptor >> score_count;
    adaptor.read_container(packet.scores, score_count);

    // Read metadata using null_terminated string deserialization
    adaptor >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    size_t bytes_read = adaptor.total_read();
    if (bytes_read < buffer.size()) {
        adaptor.skip(buffer.size() - bytes_read);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input buffer
    std::vector<uint8_t> buffer_copy(buffer.begin(), buffer.end());
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer_copy);

    PacketInfo info;

    // Use span() for packet_id (zero-copy view of first 4 bytes)
    auto id_span = adaptor.span<uint32_t>(1);
    info.packet_id = *id_span.data();

    // Read username using prefixed adaptor to get string_view
    adaptor >> hexi::prefixed(info.username);

    // Skip the scores vector without reading its elements
    uint32_t score_count;
    adaptor >> score_count;
    adaptor.skip(score_count * sizeof(uint32_t));

    return info;
}
```

## Key Implementation Details:

### For `deserialize_packet`:
1. **Buffer Adaptor Creation**: Created `buffer_adaptor` from the input buffer using a copy since the original is const
2. **Arithmetic Deserialization**: Used `operator>>` for `packet_id` as arithmetic type
3. **Prefixed String**: Used `hexi::prefixed` adaptor for username deserialization
4. **Vector Reading**: Read count first, then used `read_container` for scores vector
5. **Null-Terminated String**: Used `hexi::null_terminated` adaptor for metadata
6. **Padding Skip**: Calculated remaining bytes and skipped them using `skip()`

### For `extract_packet_info`:
1. **Span Usage**: Used `span<uint32_t>(1)` for zero-copy packet_id access
2. **Prefixed String View**: Used `hexi::prefixed` adaptor to get `string_view` of username
3. **Score Skipping**: Read count but skipped the actual data using `skip()`
4. **Efficient Extraction**: Only extracted necessary information without full deserialization

