DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor from the input span
    // Note: Need to create a non-const view since buffer_adaptor expects mutable buffer
    auto mutable_buffer = std::span<uint8_t>(const_cast<uint8_t*>(buffer.data()), buffer.size());
    hexi::buffer_adaptor adaptor(mutable_buffer);

    DataResult result;

    // Use buffer_adaptor's preview function to read the first byte (data_type) without advancing read pointer
    result.data_type = adaptor.preview<uint8_t>();

    // Calculate the total required bytes: item_count (uint32_t) + (item_count * sizeof(item))
    uint32_t item_count;
    size_t total_required_bytes;

    // Check if buffer has enough data using buffer_adaptor's size() function
    if (adaptor.size() < sizeof(uint32_t)) {
        return result; // Not enough data for item_count
    }

    // Read item_count using binary_stream
    hexi::binary_stream stream(adaptor);
    stream.get(&item_count, 1);

    // Calculate total required bytes based on data_type
    if (result.data_type == 0) {
